// Asignar nivel EMERGENTE y puntos iniciales
const body = $input.first().json.body || {};
return [{
  json: {
    tenant_id:          body.tenant_id || null,
    nombre:             body.nombre || 'Fan',
    telefono:           body.telefono || null,
    email:              body.email || null,
    telegram_chat_id:   body.telegram_chat_id || null,
    nivel:              'EMERGENTE',
    puntos:             body.referido_por ? 25 : 0,  // bonus por referido
    referido_por:       body.referido_por || null,
    artista_slug:       body.artista_slug || null,
    source:             body.source || 'telegram',
  }
}];
